#include <stdio.h>

void moveZeroes(int *nums, int n) {
    int pos = 0;
    for (int i = 0; i < n; ++i) {
        if (nums[i] != 0) {
            nums[pos++] = nums[i];
        }
    }
    while (pos < n) {
        nums[pos++] = 0;
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int nums[10000];
        for (int i = 0; i < N; ++i) scanf("%d", &nums[i]);
        moveZeroes(nums, N);
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%d", nums[i]);
        }
        if (T) printf("\n");
    }
    return 0;
}

