import sys

def moveZeroes(nums):
    pos = 0
    for i, v in enumerate(nums):
        if v != 0:
            nums[pos] = v
            pos += 1
    while pos < len(nums):
        nums[pos] = 0
        pos += 1

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    outputs = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        moveZeroes(arr)
        outputs.append(' '.join(map(str, arr)))
    sys.stdout.write('\n'.join(outputs))

if __name__ == "__main__":
    main()

